module Compare(
    input  [31:0] A,
    input  [31:0] B,
    output EQ,
    output GZ,
    output LZ,
    output GEZ,
    output LEZ
    );
    wire   ZeroA = (A == 32'b0);
  assign LEZ = ( A[31] |  ZeroA);
  assign GEZ =  ~A[31];
  assign LZ  =   A[31];
  assign GZ  = (~A[31] & ~ZeroA);
  assign EQ  = ( A == B);
endmodule
